import random
import string

class CacheUser(HttpUser):
    wait_time = between(0.1, 0.5)

    def on_start(self):
        self.cache = self.client.get("/cache/init").json()

    @task
    def get_key(self):
        key = random.choice(list(self.cache.keys()))
