# Tests unitaires
class TestLRUCacheWithTTL:
    def test_cache_get_set_nominal(self):
        cache = LRUCacheWithTTL(max_size=10, ttl=1.0)
        cache.set("key1", "value1")
        assert cache.get("key1") == "value1"
        assert cache.get("key2") is None

    def test_cache_ttl_expiry_nominal(self):
        cache = LRUCacheWithTTL(max_size=10, ttl=0.5)
        cache.set("key1", "value1")
        time.sleep(1.0)
        assert cache.get("key1") is None

    def test_cache_lru_eviction_nominal(self):
        cache = LRUCacheWithTTL(max_size=2, ttl=10.0)
        cache.set("key1", "value1")
        cache.set("key2", "value2")
        cache.set("key3", "value3")
        assert cache.get("key1") is None
        assert cache.get("key2") == "value2"
        assert cache.get("key3") == "value3"

    def test_cache_thread_safety_concurrent(self):
        cache = LRUCacheWithTTL(max_size=100, ttl=10.0)
        def worker():
            for i in range(1000):
                cache.set(f"key{i}", f"value{i}")
                _ = cache.get(f"key{i}")
        threads = [threading.Thread(target=worker) for _ in range(10)]
        for t in threads:
            t.start()
        for t in threads:
            t.join()
        assert len(cache) <= 100

    def test_cache_deadlock_prevention(self):
        cache = LRUCacheWithTTL(max_size=10, ttl=1.0)
        def worker():
            for _ in range(100):
                with cache.lock:
                    cache.set("key", "value")
                    _ = cache.get("key")
        threads = [threading.Thread(target=worker) for _ in range(10)]
        for t in threads:
            t.start()
        for t in threads:
            t.join()
        assert len(cache) == 1

    def test_cache_max_size_edge_case(self):
        cache = LRUCacheWithTTL(max_size=1, ttl=10.0)
        cache.set("key1", "value1")
        cache.set("key2", "value2")
        assert cache.get("key1") is None
        assert cache.get("key2") == "value2"

    def test_cache_ttl_zero_edge_case(self):
        cache = LRUCacheWithTTL(max_size=10, ttl=0.0)
        cache.set("key1", "value1")
        assert cache.get("key1") is None

    def test_cache_negative_ttl_exception(self):
        with pytest.raises(ValueError):
            LRUCacheWithTTL(max_size=10, ttl=-1.0)

    def test_cache_zero_max_size_exception(self):
        with pytest.raises(ValueError):
            LRUCacheWithTTL(max_size=0, ttl=10.0)


# Benchmarks de performance
@pytest.mark.benchmark
class TestCachePerformance:
    def test_benchmark_cache_get(self, benchmark):
        cache = LRUCacheWithTTL(max_size=1000, ttl=60.0)
        cache.set("key", "value")
        result = benchmark(lambda: cache.get("key"))
        assert result == "value"

    def test_benchmark_cache_set(self, benchmark):
        cache = LRUCacheWithTTL(max_size=1000, ttl=60.0)
        benchmark(lambda: cache.set("key", "value"))

    def test_benchmark_cache_concurrent_get_set(self, benchmark):
        cache = LRUCacheWithTTL(max_size=1000, ttl=60.0)
        def worker():
            for _ in range(100):
                cache.set("key", "value")
                _ = cache.get("key")
        benchmark.pedantic(worker, iterations=10, rounds=10)

